<script>export let label='';export let disabled=false;export let value='';export let placeholder='';export let error='';export let description='';let open=false;let selected=value;$: id=(label||'select').toLowerCase().replace(/[^a-z0-9]+/g,'-')+'-listbox';const options=["Apple","Banana","Cherry"];function key(e){if(['ArrowDown','Enter',' '].includes(e.key)){e.preventDefault();open=true}else if(e.key==='Escape')open=false}function choose(v){selected=v;open=false}</script>
<div class="kumo-field"><label for={id+'-trigger'}>{label}</label><button type="button" role="combobox" id={id+'-trigger'} aria-controls={id} aria-expanded={open} aria-haspopup="listbox" {disabled} onclick={()=>open=!open} onkeydown={key} class="kumo-trigger"><span>{selected||placeholder}</span><svg aria-hidden="true" width="16" height="16" viewBox="0 0 16 16"><path fill="currentColor" d="m4 6 4 4 4-4z"/></svg></button>{#if open}<ul id={id} role="listbox">{#each options as o}<li role="option" aria-selected={selected===o} tabindex="-1" onclick={()=>choose(o)} onkeydown={(e)=>['Enter',' '].includes(e.key)&&choose(o)}>{o}</li>{/each}</ul>{/if}{#if error}<p class="error">{error}</p>{:else if description}<p class="description">{description}</p>{/if}</div>
